import React, { useRef, memo, useState, useCallback, useEffect } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Brain, Zap, Eye, CheckCircle2, Play, RotateCcw, Sparkles } from 'lucide-react';
import ExpandableSection from '@/components/ExpandableSection';
import Badge from '@/components/Badge';

interface SlideProps {
  isActive: boolean;
}

/* ── Simulation step data ── */
interface SimStep {
  type: 'THINK' | 'ACT' | 'OBSERVE' | 'DONE';
  icon: typeof Brain;
  color: string;
  bgColor: string;
  title: string;
  content: string;
  codeBlock?: { label: string; lines: string[] };
}

const SIM_STEPS: SimStep[] = [
  {
    type: 'THINK',
    icon: Brain,
    color: 'var(--primary)',
    bgColor: 'rgba(0,102,204,0.08)',
    title: '🧠 思考',
    content: '用户要求生成网络运维周报。我需要：1) 查询本周告警数据 2) 获取网络性能指标 3) 生成报告',
  },
  {
    type: 'ACT',
    icon: Zap,
    color: 'var(--accent)',
    bgColor: 'rgba(255,107,53,0.08)',
    title: '⚡ 行动：调用 query_database 工具',
    content: '执行SQL查询获取本周告警数据',
    codeBlock: {
      label: '📤 请求',
      lines: ['{ tool: "query_database",', '  sql: "SELECT * FROM alerts WHERE week=\'current\'" }'],
    },
  },
  {
    type: 'OBSERVE',
    icon: Eye,
    color: 'var(--success)',
    bgColor: 'rgba(34,197,94,0.08)',
    title: '👁 观察',
    content: '本周共156条告警，其中3条严重、23条警告。严重告警集中在SPN网络。',
    codeBlock: {
      label: '📥 返回',
      lines: ['{ rows: 156, critical: 3, warning: 23, normal: 130 }'],
    },
  },
  {
    type: 'THINK',
    icon: Brain,
    color: 'var(--primary)',
    bgColor: 'rgba(0,102,204,0.08)',
    title: '🧠 思考',
    content: '已获取告警数据。现在需要获取网络性能指标来补充周报内容。',
  },
  {
    type: 'ACT',
    icon: Zap,
    color: 'var(--accent)',
    bgColor: 'rgba(255,107,53,0.08)',
    title: '⚡ 行动：调用 get_network_metrics 工具',
    content: '获取SPN核心网性能数据',
    codeBlock: {
      label: '📤 请求',
      lines: ['{ tool: "get_network_metrics",', '  target: "SPN_CORE", period: "7d" }'],
    },
  },
  {
    type: 'DONE',
    icon: CheckCircle2,
    color: 'var(--success)',
    bgColor: 'rgba(34,197,94,0.08)',
    title: '✅ 任务完成',
    content: '已整合告警数据与性能指标，生成完整的网络运维周报并发送至飞书群。',
  },
];

/**
 * Slide 08 — ReAct：当模型拥有了记忆、知识、行动能力
 * Full interactive ReAct cycle simulation with step-by-step animation
 */
const Slide08_ReAct: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [currentStep, setCurrentStep] = useState(-1); // -1 = not started
  const [displayedText, setDisplayedText] = useState<Record<number, string>>({});
  const [isRunning, setIsRunning] = useState(false);
  const stepRefs = useRef<(HTMLDivElement | null)[]>([]);
  const typingTimers = useRef<ReturnType<typeof setTimeout>[]>([]);

  /* Clear all typing timers on unmount */
  useEffect(() => {
    return () => typingTimers.current.forEach(clearTimeout);
  }, []);

  /* Reset simulation */
  const handleReset = useCallback(() => {
    typingTimers.current.forEach(clearTimeout);
    typingTimers.current = [];
    setCurrentStep(-1);
    setDisplayedText({});
    setIsRunning(false);
  }, []);

  /* Animate a single step's text with typing effect */
  const typeText = useCallback((stepIndex: number, text: string) => {
    return new Promise<void>((resolve) => {
      let charIndex = 0;
      const tick = () => {
        charIndex += 2; // 2 chars per tick for speed
        const partial = text.slice(0, charIndex);
        setDisplayedText((prev) => ({ ...prev, [stepIndex]: partial }));
        if (charIndex < text.length) {
          const timer = setTimeout(tick, 18);
          typingTimers.current.push(timer);
        } else {
          resolve();
        }
      };
      tick();
    });
  }, []);

  /* Run the full simulation */
  const handleStart = useCallback(async () => {
    if (isRunning) return;
    handleReset();
    setIsRunning(true);

    for (let i = 0; i < SIM_STEPS.length; i++) {
      setCurrentStep(i);

      // Scroll the new step into view
      await new Promise<void>((resolve) => {
        requestAnimationFrame(() => {
          stepRefs.current[i]?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
          resolve();
        });
      });

      // GSAP entrance for the step card
      const el = stepRefs.current[i];
      if (el) {
        gsap.fromTo(
          el,
          { opacity: 0, x: -40, scale: 0.95 },
          { opacity: 1, x: 0, scale: 1, duration: 0.5, ease: 'back.out(1.4)' }
        );
      }

      // Typing animation for content
      await typeText(i, SIM_STEPS[i].content);
      await new Promise<void>((resolve) => setTimeout(resolve, 400));

      // If there's a code block, animate it in
      if (SIM_STEPS[i].codeBlock && el) {
        const codeEl = el.querySelector('.step-code-block');
        if (codeEl) {
          gsap.fromTo(
            codeEl,
            { opacity: 0, y: 10 },
            { opacity: 1, y: 0, duration: 0.4, ease: 'power2.out' }
          );
        }
        await new Promise<void>((resolve) => setTimeout(resolve, 600));
      }
    }

    setIsRunning(false);
  }, [isRunning, handleReset, typeText]);

  /* GSAP entrance for header elements */
  useGSAP(
    () => {
      if (!isActive || !containerRef.current) return;

      const ctx = gsap.context(() => {
        const tl = gsap.timeline({ delay: 0.15 });

        tl.fromTo(
          '.s08-badge',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          0
        );

        tl.fromTo(
          '.s08-title',
          { opacity: 0, y: 30 },
          { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' },
          0.1
        );

        tl.fromTo(
          '.s08-subtitle',
          { opacity: 0, y: 15 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          0.3
        );

        tl.fromTo(
          '.s08-controls',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          0.5
        );

        tl.fromTo(
          '.s08-footer',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          0.7
        );

        tl.fromTo(
          '.s08-expandable',
          { opacity: 0 },
          { opacity: 1, duration: 0.5 },
          0.9
        );
      }, containerRef);

      return () => ctx.revert();
    },
    { scope: containerRef, dependencies: [isActive] }
  );

  return (
    <section
      ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-16 overflow-hidden"
      style={{ backgroundColor: 'var(--bg-primary)' }}
    >
      <div className="w-full max-w-5xl mx-auto flex flex-col items-center">
        {/* Badge */}
        <div className="s08-badge mb-4 opacity-0">
          <Badge variant="primary">
            <Brain className="w-3.5 h-3.5 mr-1.5 inline" strokeWidth={2} />
            <span>ReAct 模式深度演示</span>
          </Badge>
        </div>

        {/* Title */}
        <h2
          className="s08-title text-h1 md:text-display-xl font-extrabold text-center opacity-0"
          style={{ color: 'var(--text-primary)' }}
        >
          ReAct：当模型拥有了记忆、知识、行动能力
        </h2>
        <p
          className="s08-subtitle text-body text-center mt-3 opacity-0"
          style={{ color: 'var(--text-secondary)' }}
        >
          点击下方按钮，观看一个完整的 ReAct 循环模拟
        </p>

        {/* Controls */}
        <div className="s08-controls mt-8 mb-6 flex items-center gap-4 opacity-0">
          <button
            onClick={handleStart}
            disabled={isRunning}
            className="flex items-center gap-2 px-6 py-3 rounded-xl text-body-sm font-bold transition-all duration-300 hover:-translate-y-0.5 disabled:opacity-50 disabled:cursor-not-allowed"
            style={{
              backgroundColor: 'var(--accent)',
              color: '#FFFFFF',
              boxShadow: '0 4px 14px rgba(255,107,53,0.35)',
            }}
          >
            <Play className="w-4 h-4" strokeWidth={2.5} fill="currentColor" />
            {currentStep === -1 ? '开始模拟' : isRunning ? '模拟中...' : '重新模拟'}
          </button>
          {currentStep >= 0 && (
            <button
              onClick={handleReset}
              className="flex items-center gap-2 px-4 py-3 rounded-xl text-body-sm font-semibold border transition-all duration-200 hover:bg-[var(--bg-accent)]"
              style={{ borderColor: 'var(--border)', color: 'var(--text-secondary)' }}
            >
              <RotateCcw className="w-4 h-4" strokeWidth={2} />
              重置
            </button>
          )}
          {currentStep >= 0 && (
            <span className="text-caption font-mono" style={{ color: 'var(--text-light)' }}>
              Step {Math.min(currentStep + 1, SIM_STEPS.length)} / {SIM_STEPS.length}
            </span>
          )}
        </div>

        {/* Simulation Steps Container */}
        <div className="w-full max-w-3xl flex flex-col gap-4 mb-8 min-h-[300px]">
          {SIM_STEPS.map((step, index) => {
            const StepIcon = step.icon;
            const isVisible = index <= currentStep;
            const isCurrent = index === currentStep;

            return (
              <div
                key={index}
                ref={(el) => { stepRefs.current[index] = el; }}
                className={`flex items-start gap-4 px-5 py-4 rounded-2xl border-2 transition-shadow duration-300 ${isCurrent ? 'shadow-card' : ''}`}
                style={{
                  opacity: isVisible ? 1 : 0,
                  borderColor: isVisible ? step.color : 'transparent',
                  backgroundColor: isVisible ? step.bgColor : 'transparent',
                  pointerEvents: isVisible ? 'auto' : 'none',
                  maxHeight: isVisible ? 500 : 0,
                  overflow: 'hidden',
                }}
              >
                {/* Step number badge */}
                <div
                  className="flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center"
                  style={{ backgroundColor: step.color, color: '#FFFFFF' }}
                >
                  <StepIcon className="w-5 h-5" strokeWidth={2.5} />
                </div>

                <div className="flex-1 min-w-0">
                  {/* Step header */}
                  <div className="flex items-center gap-2 mb-1.5">
                    <span
                      className="text-caption font-bold uppercase tracking-wider"
                      style={{ color: step.color }}
                    >
                      {step.type === 'DONE' ? 'COMPLETE' : step.type}
                    </span>
                    {isCurrent && isRunning && (
                      <span className="inline-block w-1.5 h-1.5 rounded-full animate-pulse" style={{ backgroundColor: step.color }} />
                    )}
                  </div>

                  {/* Step title */}
                  <h4 className="text-body-sm font-semibold mb-1" style={{ color: 'var(--text-primary)' }}>
                    {step.title}
                  </h4>

                  {/* Typed content */}
                  <p className="text-body-sm leading-relaxed" style={{ color: 'var(--text-primary)' }}>
                    {displayedText[index] || ''}
                    {isCurrent && isRunning && (
                      <span className="inline-block w-0.5 h-4 ml-0.5 animate-pulse" style={{ backgroundColor: step.color }} />
                    )}
                  </p>

                  {/* Code block (if any) */}
                  {step.codeBlock && index <= currentStep && (
                    <div
                      className="step-code-block mt-3 rounded-lg p-3 font-mono text-caption"
                      style={{
                        backgroundColor: 'rgba(0,0,0,0.05)',
                        border: `1px solid ${step.color}33`,
                      }}
                    >
                      <span className="font-bold text-body-sm" style={{ color: step.color }}>
                        {step.codeBlock.label}
                      </span>
                      {step.codeBlock.lines.map((line, li) => (
                        <div key={li} className="mt-1" style={{ color: 'var(--text-secondary)' }}>
                          {line}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

